        .price-card h3 { font-size: 1.5rem; font-weight: 700; }
        .price { font-size: 2.5rem; font-weight: 800; color: var(--secondary); margin: 1rem 0; }
        .price span { font-size: 1rem; color: var(--text-muted); font-weight: 400; }
        .price-features { list-style: none; margin: 2rem 0; flex-grow: 1; }
        .price-features li { margin-bottom: 0.75rem; color: var(--text-muted); display: flex; align-items: center; gap: 0.5rem; }
        .price-features li svg { width: 20px; height: 20px; fill: #10b981; flex-shrink: 0; }

        /* Footer */
        footer { background: var(--secondary); color: #94a3b8; padding: 4rem 0 2rem; font-size: 0.9rem; }
        .footer-grid { grid-template-columns: 2fr 1fr 1fr; margin-bottom: 2rem; }
        .footer-bottom { border-top: 1px solid #334155; padding-top: 2rem; display: flex; justify-content: space-between; }
        .footer-links { display: flex; gap: 2rem; }

        /* Responsive */
        @media (max-width: 768px) {
            .hero h1 { font-size: 2.25rem; }
            .footer-grid { grid-template-columns: 1fr; gap: 2rem; }
            .footer-bottom { flex-direction: column; gap: 1.5rem; text-align: center; }
        }
    </style>
