            <nav>
                <a href="#features" style="color: var(--text-main); text-decoration: none; margin-right: 2rem; font-weight: 500;">Features</a>
                <a href="#pricing" style="color: var(--text-main); text-decoration: none; font-weight: 500;">Pricing</a>
                <a href="#contact" class="cta-btn" style="padding: 0.5rem 1.25rem; font-size: 0.9rem;">Get Started</a>
            </nav>
        </div>
    </header>

    <main>
        <!-- Hero Section -->
        <section class="hero">
            <div class="container"></div></section></main></body></html>

